// Fetch Watchlist — returns the 7 AI watchlist companies.
// Header auth on the webhook validates X-Pipeline-Secret = $env.PIPELINE_SECRET.
const watchlist = [
  { ticker: "NVDA",  company: "NVIDIA",    org: "NVIDIA" },
  { ticker: "AMD",   company: "AMD",       org: "GPUOpen-Tools" },
  { ticker: "INTC",  company: "Intel",     org: "intel" },
  { ticker: "GOOGL", company: "Google",    org: "google" },
  { ticker: "AAPL",  company: "Apple",     org: "apple" },
  { ticker: "MSFT",  company: "Microsoft", org: "microsoft" },
  { ticker: "META",  company: "Meta",      org: "facebookresearch" }
];

return watchlist.map((w, idx) => ({ json: { ...w, index: idx } }));

// Parse & Calculate Velocity
// Merge (mergeByPosition) yields one item per input position 0-6.
// Each item is the GitHub /orgs/{org}/repos response (an array of repos)
// OR a single repo object depending on how n8n wrapped it. We map by index.
const watchlist = [
  { ticker: "NVDA",  company: "NVIDIA",    org: "NVIDIA" },
  { ticker: "AMD",   company: "AMD",       org: "GPUOpen-Tools" },
  { ticker: "INTC",  company: "Intel",     org: "intel" },
  { ticker: "GOOGL", company: "Google",    org: "google" },
  { ticker: "AAPL",  company: "Apple",     org: "apple" },
  { ticker: "MSFT",  company: "Microsoft", org: "microsoft" },
  { ticker: "META",  company: "Meta",      org: "facebookresearch" }
];

const items = $input.all();
const now = Date.now();
const THIRTY_DAYS = 30 * 24 * 60 * 60 * 1000;
const out = [];

for (let i = 0; i < watchlist.length; i++) {
  const wl = watchlist[i];
  const raw = items[i] ? items[i].json : {};

  // GitHub returns an array of repos. n8n may store it under a key or as the
  // object itself. Normalize to an array of repo objects.
  let repos = [];
  if (Array.isArray(raw)) {
    repos = raw;
  } else if (Array.isArray(raw.data)) {
    repos = raw.data;
  } else if (raw && raw.name && raw.full_name) {
    repos = [raw];
  } else if (raw && typeof raw === 'object') {
    // Fallback: collect numeric-keyed repo objects
    const vals = Object.values(raw).filter(v => v && v.name && v.full_name);
    if (vals.length) repos = vals;
  }

  const activeRepos = repos.filter(r => {
    if (!r.pushed_at) return false;
    return (now - new Date(r.pushed_at).getTime()) <= THIRTY_DAYS;
  });

  const total_stars = repos.reduce((s, r) => s + (r.stargazers_count || 0), 0);

  let top_repo = null;
  let maxStars = -1;
  for (const r of repos) {
    if ((r.stargazers_count || 0) > maxStars) {
      maxStars = r.stargazers_count || 0;
      top_repo = r.name;
    }
  }

  const languages = [...new Set(repos.map(r => r.language).filter(Boolean))];
  const repo_names = repos.slice(0, 10).map(r => r.name);

  out.push({
    json: {
      ticker: wl.ticker,
      company: wl.company,
      org: wl.org,
      total_repos_active: activeRepos.length,
      total_stars,
      top_repo,
      languages,
      repo_names
    }
  });
}

return out;

// Load Previous Run from Supabase
// Pulls the most recent 7 signal rows to build a ticker -> previous metrics map.
const SUPABASE_URL = $env.SUPABASE_URL;
const SUPABASE_KEY = $env.SUPABASE_KEY;

const currentItems = $input.all();

let prevMap = {};
try {
  const url = `${SUPABASE_URL}/rest/v1/github_signals?select=ticker,total_repos_active,total_stars,run_timestamp&order=run_timestamp.desc&limit=7`;
  const res = await this.helpers.httpRequest({
    method: 'GET',
    url,
    headers: {
      apikey: SUPABASE_KEY,
      Authorization: `Bearer ${SUPABASE_KEY}`,
      Accept: 'application/json'
    },
    json: true
  });
  const rows = Array.isArray(res) ? res : [];
  for (const row of rows) {
    // Keep only the first (most recent) row seen per ticker.
    if (!prevMap[row.ticker]) {
      prevMap[row.ticker] = {
        total_repos_active: row.total_repos_active,
        total_stars: row.total_stars,
        run_timestamp: row.run_timestamp
      };
    }
  }
} catch (e) {
  // No previous data / table empty / network error -> treat as first run.
  prevMap = {};
}

// Attach the previous map to every current company record.
return currentItems.map(item => ({
  json: {
    ...item.json,
    _previous: prevMap[item.json.ticker] || null
  }
}));

// Calculate Week-over-Week Delta
const out = [];
for (const item of $input.all()) {
  const j = item.json;
  const prev = j._previous;
  const current = j.total_repos_active || 0;
  const currentStars = j.total_stars || 0;

  const is_first_run = !prev;
  const prevRepos = prev ? (prev.total_repos_active || 0) : 0;
  const prevStars = prev ? (prev.total_stars || 0) : 0;

  const repos_delta = current - prevRepos;
  const stars_delta = currentStars - prevStars;

  let velocity_direction;
  if (is_first_run) {
    velocity_direction = 'STABLE';
  } else if (repos_delta > 2) {
    velocity_direction = 'ACCELERATING';
  } else if (repos_delta < -2) {
    velocity_direction = 'DECELERATING';
  } else {
    velocity_direction = 'STABLE';
  }

  let delta_pct;
  if (is_first_run || prevRepos === 0) {
    delta_pct = 0;
  } else {
    delta_pct = parseFloat((((current - prevRepos) / prevRepos) * 100).toFixed(1));
  }

  const { _previous, ...rest } = j;
  out.push({
    json: {
      ...rest,
      repos_delta,
      stars_delta,
      velocity_direction,
      delta_pct,
      is_first_run,
      prev_total_repos_active: prevRepos,
      prev_total_stars: prevStars
    }
  });
}
return out;

// Aggregate for Groq
// Build a compact summary of all 7 companies for the classifier, and carry
// the full per-company records forward so later nodes can re-read them.
const companies = $input.all().map(i => i.json);

const summary = companies.map(c => ({
  ticker: c.ticker,
  company: c.company,
  total_repos_active: c.total_repos_active,
  total_stars: c.total_stars,
  top_repo: c.top_repo,
  languages: c.languages,
  repo_names: c.repo_names,
  velocity_direction: c.velocity_direction,
  delta_pct: c.delta_pct,
  repos_delta: c.repos_delta
}));

return [{
  json: {
    companies,        // full records preserved for downstream nodes
    summary,          // compact slice for the LLM
    summary_json: JSON.stringify(summary, null, 2)
  }
}];

