// Parse Groq Response
let parsed = null;
try {
  const resp = $input.first().json;
  let content = resp?.choices?.[0]?.message?.content || '';
  // Strip ```json ... ``` or ``` ... ``` fences.
  content = content.trim()
    .replace(/^```json\s*/i, '')
    .replace(/^```\s*/i, '')
    .replace(/```\s*$/i, '')
    .trim();
  parsed = JSON.parse(content);
} catch (e) {
  parsed = null;
}

// Pull the previously-computed company data from Aggregate for Groq.
const agg = $('Aggregate for Groq').first().json;
const companies = agg.companies || [];

return [{
  json: {
    groq_parsed: parsed,        // array or null
    groq_ok: parsed !== null,
    companies
  }
}];

// Signal Assembler
// Merge Groq output into company records by ticker, mint one agent_run_id
// for the whole run, compute the ISO week, and emit one item per company.

function uuidv4() {
  // Deterministic-ish RFC4122 v4 generator (crypto-free for n8n sandbox).
  let d = new Date().getTime();
  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, function (c) {
    const r = (d + Math.random() * 16) % 16 | 0;
    d = Math.floor(d / 16);
    return (c === 'x' ? r : (r & 0x3) | 0x8).toString(16);
  });
}

function isoWeek(date) {
  const d = new Date(Date.UTC(date.getUTCFullYear(), date.getUTCMonth(), date.getUTCDate()));
  const dayNum = (d.getUTCDay() + 6) % 7; // Mon=0..Sun=6
  d.setUTCDate(d.getUTCDate() - dayNum + 3); // nearest Thursday
  const firstThursday = new Date(Date.UTC(d.getUTCFullYear(), 0, 4));
  const firstDayNum = (firstThursday.getUTCDay() + 6) % 7;
  firstThursday.setUTCDate(firstThursday.getUTCDate() - firstDayNum + 3);
  const week = 1 + Math.round((d - firstThursday) / (7 * 24 * 60 * 60 * 1000));
  return `${d.getUTCFullYear()}-W${String(week).padStart(2, '0')}`;
}

const input = $input.first().json;
const companies = input.companies || [];
const groq = Array.isArray(input.groq_parsed) ? input.groq_parsed : [];

const groqByTicker = {};
for (const g of groq) {
  if (g && g.ticker) groqByTicker[g.ticker] = g;
}

const run_timestamp = new Date().toISOString();
const agent_run_id = uuidv4();
const run_week = isoWeek(new Date());

let acceleratingCount = 0;
let deceleratingCount = 0;
let riskFlagCount = 0;

const records = companies.map(c => {
  const g = groqByTicker[c.ticker] || {};
  const risk_flag = g.risk_flag === true;

  if (c.velocity_direction === 'ACCELERATING') acceleratingCount++;
  if (c.velocity_direction === 'DECELERATING') deceleratingCount++;
  if (risk_flag) riskFlagCount++;

  return {
    ticker: c.ticker,
    company: c.company,
    run_timestamp,
    run_week,
    agent_run_id,
    total_repos_active: c.total_repos_active,
    total_stars: c.total_stars,
    top_repo: c.top_repo,
    languages: c.languages || [],
    repo_names: c.repo_names || [],
    velocity_direction: c.velocity_direction,
    delta_pct: c.delta_pct,
    repos_delta: c.repos_delta,
    stars_delta: c.stars_delta,
    activity_classification: g.activity_classification || 'MODERATE',
    momentum_signal: g.momentum_signal || 'MAINTAINING',
    key_observation: g.key_observation || 'No classification available for this run.',
    notable_repos: Array.isArray(g.notable_repos) ? g.notable_repos : [],
    risk_flag,
    is_first_run: c.is_first_run === true,
    // run-level summary carried on every record for downstream report nodes
    _run_summary: { acceleratingCount, deceleratingCount, riskFlagCount, agent_run_id, run_week, run_timestamp }
  };
});

// Re-stamp the final (complete) run summary onto every record.
const runSummary = { acceleratingCount, deceleratingCount, riskFlagCount, agent_run_id, run_week, run_timestamp };
return records.map(r => ({ json: { ...r, _run_summary: runSummary } }));

// Generate Report — build the full markdown signal report.
const records = $input.all().map(i => i.json);
if (!records.length) {
  return [{ json: { report: '# GitHub Commit Velocity Tracker — No data', runId: null, companies_tracked: 0, accelerating_count: 0, decelerating_count: 0, risk_flag_count: 0 } }];
}

const summary = records[0]._run_summary || {};
const runId = summary.agent_run_id || 'unknown';
const run_week = summary.run_week || 'unknown';
const run_timestamp = summary.run_timestamp || new Date().toISOString();

const acceleratingCount = summary.acceleratingCount || 0;
const deceleratingCount = summary.deceleratingCount || 0;
const riskFlagCount = summary.riskFlagCount || 0;
const stableCount = records.filter(r => r.velocity_direction === 'STABLE').length;

const esc = (v) => (v === null || v === undefined || v === '') ? '—' : String(v);
const pct = (r) => `${r.delta_pct > 0 ? '+' : ''}${esc(r.delta_pct)}%`;
const joinArr = (a) => (Array.isArray(a) && a.length) ? a.join(', ') : '—';

let md = '';
md += '# GitHub Commit Velocity Tracker — Signal Report\n\n';
md += `**Run ID:** \`${runId}\`  \n`;
md += `**Generated:** ${run_timestamp}  \n`;
md += `**Period:** ${run_week}\n\n`;
md += '---\n\n';

// Executive Summary
md += '## Executive Summary\n\n';
md += '| Metric | Value |\n|---|---|\n';
md += `| Companies tracked | ${records.length} |\n`;
md += `| Accelerating | ${acceleratingCount} |\n`;
md += `| Stable | ${stableCount} |\n`;
md += `| Decelerating | ${deceleratingCount} |\n`;
md += `| Risk flags | ${riskFlagCount} |\n\n`;

// Engineering Velocity Rankings
md += '## Engineering Velocity Rankings\n\n';
const ranked = [...records].sort((a, b) => (b.total_repos_active || 0) - (a.total_repos_active || 0));
ranked.forEach((r, i) => {
  md += `### ${i + 1}. ${esc(r.company)} (${esc(r.ticker)})\n\n`;
  md += `- **Velocity:** ${esc(r.velocity_direction)} (${pct(r)})\n`;
  md += `- **Activity:** ${esc(r.activity_classification)}\n`;
  md += `- **Momentum:** ${esc(r.momentum_signal)}\n`;
  md += `- **Active repos:** ${esc(r.total_repos_active)} | **Stars:** ${esc(r.total_stars)}\n`;
  md += `- **Observation:** ${esc(r.key_observation)}\n`;
  md += `- **Top repo:** ${esc(r.top_repo)}\n`;
  md += `- **Notable repos:** ${joinArr(r.notable_repos)}\n`;
  md += `- **Risk flag:** ${r.risk_flag ? '⚠️ YES' : 'no'}\n\n`;
});

// Accelerating Companies
md += '## Accelerating Companies\n\n';
const accel = records.filter(r => r.velocity_direction === 'ACCELERATING');
if (accel.length) {
  accel.forEach(r => { md += `- **${esc(r.company)} (${esc(r.ticker)})** — ${pct(r)}, ${esc(r.activity_classification)} — ${esc(r.key_observation)}\n`; });
} else {
  md += '_No companies accelerating this period._\n';
}
md += '\n';

// Risk Flags
md += '## Risk Flags\n\n';
const risks = records.filter(r => r.risk_flag === true);
if (risks.length) {
  risks.forEach(r => { md += `- ⚠️ **${esc(r.company)} (${esc(r.ticker)})** — ${esc(r.momentum_signal)} — ${esc(r.key_observation)}\n`; });
} else {
  md += '_No risk flags this period._\n';
}
md += '\n';

// Week-over-Week Delta Table
md += '## Week-over-Week Delta Table\n\n';
md += '| Company | Ticker | Repos This Week | Repos Last Week | Delta | Direction |\n';
md += '|---|---|---|---|---|---|\n';
records.forEach(r => {
  const last = (r.total_repos_active || 0) - (r.repos_delta || 0);
  md += `| ${esc(r.company)} | ${esc(r.ticker)} | ${esc(r.total_repos_active)} | ${r.is_first_run ? '—' : last} | ${r.repos_delta > 0 ? '+' : ''}${esc(r.repos_delta)} | ${esc(r.velocity_direction)} |\n`;
});
md += '\n';

// Language Landscape
md += '## Language Landscape\n\n';
records.forEach(r => {
  md += `- **${esc(r.company)} (${esc(r.ticker)}):** ${joinArr(r.languages)}\n`;
});
md += '\n';

// Known Limitations
md += '## Known Limitations\n\n';
md += '- Top 10 repos per org only — deeper backlogs are not sampled.\n';
md += '- Repos delta is an activity proxy, not a raw commit count.\n';
md += '- First run has no week-over-week comparison.\n';
md += '- GitHub token required (5,000 req/hr authenticated).\n\n';

md += '---\n\n';
md += '_Mycroft — GitHub Commit Velocity Tracker | Agent 4_  \n';
md += '_Stack: n8n + GitHub REST API + Groq + Supabase_\n';

return [{
  json: {
    report: md,
    runId,
    companies_tracked: records.length,
    accelerating_count: acceleratingCount,
    decelerating_count: deceleratingCount,
    risk_flag_count: riskFlagCount
  }
}];
